1	import { useTranslation } from 'react-i18next'
2	import { Modal, Form, Input, Select, Tooltip } from '@arco-design/web-react'
3	import { handelFieldNameShow } from '@/utils/tools'
4	const FormItem = Form.Item
5	const Option = Select.Option
6	const { TextArea } = Input
7	
8	interface LinkControlModalProps {
9	  visible: boolean
10	  controlOptionList: any[]
11	  effectivenessItemList?: any[]
12	  onOk: (values: {
13	    controlId: string
14	    checkResult: string | number
15	    noteAr: string
16	    note: string
17	    controlData: any
18	  }) => void
19	  onCancel: () => void
20	  loading?: boolean
21	  confirmLoading?: boolean
22	  form: any
23	}
24	
25	const LinkControlModal = ({
26	  loading,
27	  visible,
28	  controlOptionList,
29	  effectivenessItemList = [],
30	  onOk,
31	  onCancel,
32	  confirmLoading,
33	  form,
34	}: LinkControlModalProps) => {
35	  const { t } = useTranslation(['risk', 'common'])
36	
37	  const handleOk = () => {
38	    form.validate().then((values: any) => {
39	      const controlData = (controlOptionList || []).find(
40	        (item: any) => (item.value || item.controlId) === values.linkControl,
41	      )
42	      // 提交后不在此清空表单,清空时机改到父组件打开弹窗时;
43	      // 关闭弹窗也由父组件在接口完成后控制。
44	      onOk({
45	        controlId: values.linkControl,
46	        checkResult: values.checkResult,
47	        noteAr: values.noteAr || '',
48	        note: values.note || '',
49	        controlData,
50	      })
51	    })
52	  }
53	
54	  const handleCancel = () => {
55	    onCancel()
56	  }
57	
58	  const renderSelectOptionLabel = (text?: string) => {
59	    const content = text || '-'
60	    return (
61	      <Tooltip content={content}>
62	        <div
63	          style={{
64	            width: '100%',
65	            overflow: 'hidden',
66	            textOverflow: 'ellipsis',
67	            whiteSpace: 'nowrap',
68	          }}
69	        >
70	          {content}
71	        </div>
72	      </Tooltip>
73	    )
74	  }
75	
76	  return (
77	    <Modal
78	      title={t('riskCreationWizard:riskDetail.linkControl')}
79	      visible={visible}
80	      onOk={handleOk}
81	      okText={t('common:btn.confirm')}
82	      confirmLoading={confirmLoading}
83	      onCancel={handleCancel}
84	      className='procedures-control-modal'
85	      autoFocus={false}
86	      focusLock={true}
87	      unmountOnExit
88	    >
89	      <Form form={form} layout='vertical'>
90	        <FormItem
91	          label={t('riskCreationWizard:riskDetail.linkControl')}
92	          field='linkControl'
93	          rules={[{ required: true, message: t('common:pleaseSelect') }]}
94	        >
95	          <Select placeholder={t('common:pleaseSelect')} loading={loading}>
96	            {(controlOptionList || []).map((item) => (
97	              <Option
98	                key={item?.value || item?.controlId}
99	                value={item?.value || item?.controlId}
100	              >
101	                {renderSelectOptionLabel(item?.label || item?.name)}
102	              </Option>
103	            ))}
104	          </Select>
105	        </FormItem>
106	        <FormItem
107	          label={t('riskCreationWizard:riskDetail.checkResult')}
108	          field='checkResult'
109	          rules={[{ required: true, message: t('common:pleaseSelect') }]}
110	        >
111	          <Select
112	            allowClear
113	            placeholder={t('common:pleaseSelect')}
114	            renderFormat={(option: any) => {
115	              const value = String(option?.value ?? option ?? '')
116	              const matchedItem = effectivenessItemList.find(
117	                (item) => String(item?.effectivenessId) === value,
118	              )
119	              const label =
120	                handelFieldNameShow(matchedItem?.name, matchedItem?.nameAr) ||
121	                value
122	
123	              return (
124	                <span style={{ color: matchedItem?.color || undefined }}>
125	                  {label}
126	                </span>
127	              )
128	            }}
129	          >
130	            {effectivenessItemList.map((item) => (
131	              <Option
132	                key={item?.effectivenessId}
133	                value={item?.effectivenessId}
134	                style={{
135	                  color: item?.color || undefined,
136	                  fontWeight: 500,
137	                }}
138	              >
139	                {handelFieldNameShow(item?.name, item?.nameAr) || '-'}
140	              </Option>
141	            ))}
142	          </Select>
143	        </FormItem>
144	        <FormItem
145	          label={t('riskCreationWizard:riskDetail.noteAr')}
146	          field='noteAr'
147	        >
148	          <TextArea
149	            placeholder={t('common:pleaseEnter')}
150	            maxLength={{ length: 500, errorOnly: false }}
151	            showWordLimit
152	            rows={3}
153	          />
154	        </FormItem>
155	        <FormItem
156	          label={t('riskCreationWizard:riskDetail.noteEn')}
157	          field='note'
158	        >
159	          <TextArea
160	            placeholder={t('common:pleaseEnter')}
161	            maxLength={{ length: 500, errorOnly: false }}
162	            showWordLimit
163	            rows={3}
164	          />
165	        </FormItem>
166	      </Form>
167	    </Modal>
168	  )
169	}
170	
171	export default LinkControlModal
